import { useNavigate } from "react-router-dom";

// ✅ No useState import (was unused)
// ✅ isFav and onFav received as props
// ✅ alt prop added to img (fixes accessibility warning)
export const Song = ({ song, isFav, onFav }) => {
  const navigate = useNavigate();

  return (
    <div className="card">
      <img
        src={song.ar}
        alt={`${song.trackName} by ${song.artistName}`} // ✅ fixes jsx-a11y warning
      />
      <div className="card-info">
        <p className="card-artist">{song.artistName}</p>
        <p className="card-title">{song.trackName}</p>
      </div>

      <button onClick={() => navigate("/player", { state: { song } })}>
        ▶ Play
      </button>

      <button
        className={`fav-btn ${isFav(song.trackId) ? "active" : ""}`}
        onClick={(e) => {
          e.stopPropagation();
          onFav(song);
        }}
      >
        {isFav(song.trackId) ? "♥" : "♡"}
      </button>
    </div>
  );
};
